import { useState, useEffect, useRef } from "react";
import { createClient } from "@supabase/supabase-js";

const supabase = createClient(
  import.meta.env.VITE_SUPABASE_URL,
  import.meta.env.VITE_SUPABASE_ANON_KEY
);

const LOGO_B64 = "data:image/png;base64,";

const NAVY = "#1B3A52";

// Estilos
const S = {
  container: { padding: "24px", fontFamily: "Arial, sans-serif" },
  title: { fontSize: 22, fontWeight: 900, color: NAVY, marginBottom: 20 },
  filters: { display: "flex", gap: 16, marginBottom: 28, alignItems: "flex-end" },
  label: { fontSize: 12, fontWeight: 700, color: "#555", marginBottom: 4, display: "block" },
  select: { padding: "8px 12px", borderRadius: 6, border: "1.5px solid #CBD5E0", fontSize: 14, minWidth: 180, color: NAVY },
  btn: { padding: "9px 24px", background: NAVY, color: "#fff", border: "none", borderRadius: 6, fontSize: 14, fontWeight: 700, cursor: "pointer" },
  btnPrint: { padding: "9px 24px", background: "#8CB43C", color: "#fff", border: "none", borderRadius: 6, fontSize: 14, fontWeight: 700, cursor: "pointer" },
  empty: { color: "#999", fontSize: 14, marginTop: 40, textAlign: "center" },
};

// ── Hoja de respuestas (para pantalla e impresión) ──────────────────
function HojaImprimible({ prueba, referencia }) {
  const titulo = `SIMULACRO ${referencia}`;

  const pageStyle = {
    width: "216mm", padding: "6mm 8mm",
    margin: "0 auto", background: "#fff", fontFamily: "Arial, sans-serif",
    fontSize: 10, color: "#111",
  };
  const globalHeader = {
    display: "flex", alignItems: "center", justifyContent: "space-between",
    borderBottom: `2.5px solid ${NAVY}`, paddingBottom: 4, marginBottom: 5,
  };
  const hdrRef = {
    fontSize: 13, fontWeight: 900, color: NAVY,
    fontFamily: "Georgia, serif", letterSpacing: "0.05em",
  };
  const hdrSub = {
    fontSize: 6, color: "#666", textTransform: "uppercase",
    letterSpacing: "0.1em", marginTop: 1, textAlign: "center",
  };
  const datosBlock = {
    marginBottom: 4, border: "1px solid #DDD", borderRadius: 3, overflow: "hidden",
  };
  const datosHeader = {
    background: NAVY, color: "#fff", display: "flex",
    alignItems: "center", gap: 8, padding: "2px 7px",
  };
  const badge = {
    background: "#fff", color: NAVY, fontWeight: 900,
    fontSize: 7.5, padding: "1px 5px", borderRadius: 2,
  };
  const datosGrid = {
    display: "flex", flexWrap: "wrap", gap: "4px 8px",
    padding: "4px 7px 5px", background: "#FAFAFA",
  };
  const datoLabel = {
    fontSize: 5.5, textTransform: "uppercase",
    letterSpacing: "0.1em", color: "#888", marginBottom: 1, display: "block",
  };
  const datoLine = { borderBottom: "1px solid #333", height: 9 };
  const sessionAreas = {
    display: "flex", gap: 4, marginBottom: 2, alignItems: "flex-start",
  };
  const areaBlock = {
    border: "1px solid #DDD", borderRadius: 3, overflow: "hidden", flex: 1,
  };
  const areaHeader = {
    display: "flex", justifyContent: "space-between", alignItems: "center",
    padding: "2px 5px", color: "#fff", background: NAVY,
  };
  const bubblesGrid = {
    display: "flex", background: "#fff", padding: 2, gap: 3,
  };
  const qRowStyle = {
    display: "flex", alignItems: "center", gap: 1.5, height: 10,
    borderBottom: "0.4px solid #F2F2F2",
  };
  const qNumStyle = {
    fontSize: 6, color: "#444", fontWeight: 700,
    width: 12, textAlign: "right", flexShrink: 0, marginRight: 1.5,
  };
  const bubbleStyle = {
    width: 10, height: 10, borderRadius: "50%", border: "0.9px solid #999",
    display: "flex", alignItems: "center", justifyContent: "center",
    flexShrink: 0, background: "#fff",
  };
  const bletStyle = { fontSize: 5.5, color: "#444", fontWeight: 700, lineHeight: 1 };

  function BubbleArea({ name, qStart, qEnd, nCols = 1 }) {
    const total = qEnd - qStart + 1;
    const rowsPerCol = Math.ceil(total / nCols);
    return (
      <div style={areaBlock}>
        <div style={areaHeader}>
          <span style={{ fontSize: 6.5, fontWeight: 900, textTransform: "uppercase", letterSpacing: "0.04em" }}>{name}</span>
          <span style={{ fontSize: 5.5, opacity: 0.85 }}>{qStart}–{qEnd}</span>
        </div>
        <div style={bubblesGrid}>
          {Array.from({ length: nCols }).map((_, col) => (
            <div key={col} style={{ flex: 1 }}>
              {Array.from({ length: rowsPerCol }).map((_, ri) => {
                const idx = col * rowsPerCol + ri;
                if (idx >= total) return null;
                const q = qStart + idx;
                return (
                  <div key={q} style={qRowStyle}>
                    <span style={qNumStyle}>{q}</span>
                    {["A","B","C","D"].map(l => (
                      <span key={l} style={bubbleStyle}>
                        <span style={bletStyle}>{l}</span>
                      </span>
                    ))}
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>
    );
  }

  function DatosBlock({ sesNum, sesLabel, totalPregs }) {
    return (
      <div style={datosBlock}>
        <div style={datosHeader}>
          <span style={badge}>Sesión {sesNum}</span>
          <span style={{ fontSize: 7, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase" }}>
            {sesLabel} Sesión &mdash; {totalPregs} preguntas
          </span>
        </div>
        <div style={datosGrid}>
          <div style={{ display:"flex", flexDirection:"column", minWidth: 110 }}>
            <span style={datoLabel}>Nombre Completo</span>
            <div style={datoLine}/>
          </div>
          <div style={{ display:"flex", flexDirection:"column", minWidth: 55 }}>
            <span style={datoLabel}>Usuario (No. Documento)</span>
            <div style={datoLine}/>
          </div>
          <div style={{ display:"flex", flexDirection:"column", minWidth: 80 }}>
            <span style={datoLabel}>Colegio</span>
            <div style={datoLine}/>
          </div>
          <div style={{ display:"flex", flexDirection:"column", minWidth: 30 }}>
            <span style={datoLabel}>Grado</span>
            <div style={datoLine}/>
          </div>
          <div style={{ display:"flex", flexDirection:"column", minWidth: 30 }}>
            <span style={datoLabel}>Salón</span>
            <div style={datoLine}/>
          </div>
        </div>
      </div>
    );
  }

  function Header({ sesLabel, totalPregs }) {
    return (
      <div style={globalHeader}>
        <div><img src={LOGO_B64} style={{ height: 22, width: "auto" }} alt="Milton Ochoa"/></div>
        <div style={{ textAlign: "center" }}>
          <div style={hdrRef}>{titulo}</div>
          <div style={hdrSub}>{sesLabel} &mdash; {totalPregs} preguntas</div>
        </div>
        <div style={{ textAlign: "right" }}>
          <div style={{ fontSize: 6, color: "#888" }}>Consulta tus resultados en</div>
          <div style={{ fontSize: 7.5, fontWeight: 700, color: NAVY }}>resultados.aamocolombia.com</div>
        </div>
      </div>
    );
  }

  return (
    <div>
      <style>{`
        * { -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; color-adjust: exact !important; }
        @media print {
          body { margin:0; padding:0; background:white; }
          .session-page { page-break-after:always; break-after:page; -webkit-break-after:page; }
          .session-page:last-child { page-break-after:auto; break-after:auto; }
          @page { size: letter portrait; margin: 0; }
        }
      `}</style>

      {/* SESIÓN 1 */}
      <div className="session-page" style={pageStyle}>
        <Header sesLabel="Primera Sesión" totalPregs="120"/>
        <DatosBlock sesNum={1} sesLabel="Primera" totalPregs="120"/>
        <div style={sessionAreas}>
          <BubbleArea name="MATEMÁTICAS"         qStart={1}  qEnd={25}  nCols={1}/>
          <BubbleArea name="LECTURA CRÍTICA"      qStart={26} qEnd={66}  nCols={2}/>
          <BubbleArea name="SOC. Y CIUDADANAS"    qStart={67} qEnd={91}  nCols={1}/>
          <BubbleArea name="CIENCIAS NATURALES"   qStart={92} qEnd={120} nCols={1}/>
        </div>
        <div style={{ display:"flex", justifyContent:"space-between", borderTop:"1px solid #DDD", paddingTop:3, marginTop:3, fontSize:6, color:"#999" }}>
          <div>Asesorías Académicas Milton Ochoa &mdash; Expertos en Evaluación</div>
          <div>{titulo} &mdash; Sesión 1 de 2</div>
        </div>
      </div>

      {/* SESIÓN 2 */}
      <div className="session-page" style={pageStyle}>
        <Header sesLabel="Segunda Sesión" totalPregs="134"/>
        <DatosBlock sesNum={2} sesLabel="Segunda" totalPregs="134"/>
        <div style={sessionAreas}>
          <BubbleArea name="MATEMÁTICAS"         qStart={1}  qEnd={25}  nCols={1}/>
          <BubbleArea name="SOC. Y CIUDADANAS"    qStart={26} qEnd={50}  nCols={1}/>
          <BubbleArea name="CIENCIAS NATURALES"   qStart={51} qEnd={79}  nCols={1}/>
          <BubbleArea name="INGLÉS"              qStart={80} qEnd={134} nCols={2}/>
        </div>
        <div style={{ display:"flex", justifyContent:"space-between", borderTop:"1px solid #DDD", paddingTop:3, marginTop:3, fontSize:6, color:"#999" }}>
          <div>Asesorías Académicas Milton Ochoa &mdash; Expertos en Evaluación</div>
          <div>{titulo} &mdash; Sesión 2 de 2</div>
        </div>
      </div>
    </div>
  );
}

// ── Componente principal ─────────────────────────────────────────────
export default function HojasRespuesta() {
  const [pruebas, setPruebas] = useState([]);
  const [referencias, setReferencias] = useState([]);
  const [selectedPrueba, setSelectedPrueba] = useState("");
  const [selectedRef, setSelectedRef] = useState("");
  const [showHoja, setShowHoja] = useState(false);
  const printRef = useRef();

  useEffect(() => {
    supabase.from("pruebas").select("tipo").then(({ data, error }) => {
      console.log("pruebas data:", data, "error:", error);
      if (data) {
        const unique = [...new Set(data.map(r => r.tipo))].filter(Boolean);
        setPruebas(unique);
      }
    });
  }, []);

  useEffect(() => {
    if (!selectedPrueba) { setReferencias([]); setSelectedRef(""); return; }
    supabase.from("pruebas").select("codigo, nombre").ilike("tipo", selectedPrueba).then(({ data, error }) => {
      console.log("referencias data:", data, "error:", error, "prueba:", selectedPrueba);
      if (data) {
        const unique = [...new Set(data.map(r => r.codigo))].filter(r => Boolean(r) && r !== "_tipo_");
        setReferencias(unique);
        setSelectedRef("");
      }
    });
    setShowHoja(false);
  }, [selectedPrueba]);

  const handleGenerar = () => {
    if (selectedPrueba && selectedRef) setShowHoja(true);
  };

  const handlePrint = () => {
    const content = printRef.current.innerHTML;
    const win = window.open("", "_blank");
    win.document.write(`
      <html><head><title>Hoja de Respuestas</title>
      <style>
        * { margin:0; padding:0; box-sizing:border-box; }
        body { background:#fff; }
        @media print {
          body { margin:0; }
          @page { size: letter; margin: 0; }
        }
      </style></head>
      <body>${content}</body></html>
    `);
    win.document.close();
    win.focus();
    setTimeout(() => { win.print(); win.close(); }, 400);
  };

  return (
    <div style={S.container}>
      <div style={S.title}>Hojas de Respuesta</div>

      {/* FILTROS */}
      <div style={S.filters}>
        <div>
          <label style={S.label}>Prueba</label>
          <select style={S.select} value={selectedPrueba} onChange={e => setSelectedPrueba(e.target.value)}>
            <option value="">-- Selecciona --</option>
            {pruebas.map(p => <option key={p} value={p}>{p}</option>)}
          </select>
        </div>
        <div>
          <label style={S.label}>Referencia</label>
          <select style={S.select} value={selectedRef} onChange={e => setSelectedRef(e.target.value)} disabled={!selectedPrueba}>
            <option value="">-- Selecciona --</option>
            {referencias.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <button style={S.btn} onClick={handleGenerar} disabled={!selectedPrueba || !selectedRef}>
          Generar Hoja
        </button>
        {showHoja && (
          <button style={S.btnPrint} onClick={handlePrint}>
            🖨️ Imprimir / Descargar PDF
          </button>
        )}
      </div>

      {/* HOJA PREVIEW */}
      {!showHoja && (
        <div style={S.empty}>Selecciona una prueba y referencia para generar la hoja de respuestas.</div>
      )}

      {showHoja && (
        <div style={{ border: "1px solid #DDD", borderRadius: 8, overflowX: "auto", boxShadow: "0 2px 12px rgba(0,0,0,0.08)" }}>
          <div ref={printRef}>
            <HojaImprimible prueba={selectedPrueba} referencia={selectedRef}/>
          </div>
        </div>
      )}
    </div>
  );
}
